import logging
from flask import request, jsonify

class Logger:
    def __init__(self):
        self.log_file = 'application.log'

    def setup_logger(self):
        formatter = logging.Formatter('%(asctime)s - %(levelname)s - %(message)s')
        handler = logging.FileHandler(self.log_file)
        handler.setFormatter(formatter)

        logger = logging.getLogger('centralized_logger')
        logger.setLevel(logging.INFO)
        logger.addHandler(handler)

        return logger

    def log_message(self, logger, message):
        if isinstance(message, str):
            level = 'INFO'
            data = {'message': message}
        elif isinstance(message, dict) and 'levelname' in message:
            level = message['levelname']
            data = message
        else:
            raise ValueError('Invalid log message format')
        
